#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        int arr[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        qsort(arr, n, sizeof(int), compare);
        int sum = 0;
        for (int i = 0; i < k; i++) {
            sum += arr[n - i - 1];
        }
        if (sum == k) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

