const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
    } else {
        input.push(line.split(' ').map(num => parseInt(num)));
    }
    i++;
    if (i == t * 2 + 1) {
        for (let j = 0; j < t; j++) {
            let n = input[j * 2][0];
            let k = input[j * 2][1];
            let arr = input[j * 2 + 1];
            arr.sort((a, b) => b - a);
            let sum = 0;
            for (let l = 0; l < k; l++) {
                sum += arr[l];
            }
            if (sum == k) {
                console.log('YES');
            } else {
                console.log('NO');
            }
        }
    }
});

